import{_ as n,o as t,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Unternehmenseinstellungen","description":"","frontmatter":{},"headers":[],"relativePath":"de/settings/company.md","filePath":"de/settings/company.md"}'),i={name:"de/settings/company.md"};function s(l,e,o,u,g,d){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="unternehmenseinstellungen" tabindex="-1">Unternehmenseinstellungen <a class="header-anchor" href="#unternehmenseinstellungen" aria-label="Permalink to &quot;Unternehmenseinstellungen&quot;">​</a></h1><p>Konfigurieren Sie Ihre Geschäftsinformationen, Ihr Branding, finanzielle Standardeinstellungen und aktivierte Funktionen.</p><h2 id="einstellungen-aufrufen" tabindex="-1">Einstellungen aufrufen <a class="header-anchor" href="#einstellungen-aufrufen" aria-label="Permalink to &quot;Einstellungen aufrufen&quot;">​</a></h2><p>Navigieren Sie zu <strong>Unternehmen</strong> in der Seitenleiste, um auf alle Einstellungen auf Unternehmensebene zuzugreifen. Die Einstellungen sind in Abschnitte unterteilt.</p><h2 id="geschaftsinformationen" tabindex="-1">Geschäftsinformationen <a class="header-anchor" href="#geschaftsinformationen" aria-label="Permalink to &quot;Geschäftsinformationen&quot;">​</a></h2><h3 id="unternehmensdaten" tabindex="-1">Unternehmensdaten <a class="header-anchor" href="#unternehmensdaten" aria-label="Permalink to &quot;Unternehmensdaten&quot;">​</a></h3><ul><li><strong>Firmenname</strong> — Ihr eingetragener Firmenname (erscheint auf allen Dokumenten)</li><li><strong>Adresse</strong> — Straße, Postleitzahl, Stadt, Land</li><li><strong>Kontakt-E-Mail</strong> — Primäre geschäftliche E-Mail-Adresse</li><li><strong>Telefon</strong> — Geschäftstelefonnummer</li></ul><h3 id="registrierung" tabindex="-1">Registrierung <a class="header-anchor" href="#registrierung" aria-label="Permalink to &quot;Registrierung&quot;">​</a></h3><ul><li><strong>USt.-Nummer</strong> — Ihre Umsatzsteuerregistrierung (z. B. NL123456789B01)</li><li><strong>Handelsregisternummer</strong> — Gewerbeanmeldungsnummer</li><li><strong>IBAN</strong> — Bankkonto für den Zahlungsempfang</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Adress-Autovervollständigung ist verfügbar — beginnen Sie zu tippen und wählen Sie aus Vorschlägen, die von Google Maps bereitgestellt werden.</p></div><h2 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h2><h3 id="logo" tabindex="-1">Logo <a class="header-anchor" href="#logo" aria-label="Permalink to &quot;Logo&quot;">​</a></h3><p>Laden Sie Ihr Firmenlogo hoch, um es zu verwenden auf:</p><ul><li>Rechnungs- und Angebots-PDFs</li><li>E-Mail-Kommunikation</li><li>Kundenportal</li><li>Öffentliche Geschäftsseite</li></ul><p>Unterstützte Formate: PNG, JPG, SVG. Verwenden Sie ein hochauflösendes Bild mit transparentem Hintergrund für beste Ergebnisse.</p><h3 id="farben" tabindex="-1">Farben <a class="header-anchor" href="#farben" aria-label="Permalink to &quot;Farben&quot;">​</a></h3><p>Legen Sie Ihre Marken-Akzentfarbe fest. Diese wird verwendet auf:</p><ul><li>PDF-Dokumenten</li><li>E-Mail-Vorlagen</li><li>Kundenseitigen Seiten</li></ul><h2 id="finanzielle-standardeinstellungen" tabindex="-1">Finanzielle Standardeinstellungen <a class="header-anchor" href="#finanzielle-standardeinstellungen" aria-label="Permalink to &quot;Finanzielle Standardeinstellungen&quot;">​</a></h2><h3 id="wahrung" tabindex="-1">Währung <a class="header-anchor" href="#wahrung" aria-label="Permalink to &quot;Währung&quot;">​</a></h3><p>Legen Sie Ihre Standardwährung fest (standardmäßig EUR). Diese gilt für neue Rechnungen und Angebote.</p><h3 id="zahlungsbedingungen" tabindex="-1">Zahlungsbedingungen <a class="header-anchor" href="#zahlungsbedingungen" aria-label="Permalink to &quot;Zahlungsbedingungen&quot;">​</a></h3><p>Legen Sie die Standard-Anzahl der Tage bis zur Fälligkeit einer Rechnung fest. Übliche Werte:</p><ul><li><strong>14 Tage</strong> — Zwei Wochen</li><li><strong>30 Tage</strong> — Ein Monat</li><li><strong>60 Tage</strong> — Zwei Monate</li></ul><p>Sie können dies pro Rechnung überschreiben.</p><h3 id="rechnungsnummerierung" tabindex="-1">Rechnungsnummerierung <a class="header-anchor" href="#rechnungsnummerierung" aria-label="Permalink to &quot;Rechnungsnummerierung&quot;">​</a></h3><p>Passen Sie an, wie Rechnungsnummern generiert werden:</p><ul><li><strong>Präfix</strong> — Text vor der Nummer (z. B. <code>INV-</code>, <code>2024-</code>)</li><li><strong>Startnummer</strong> — Die erste Nummer in der Sequenz</li><li><strong>Automatische Erhöhung</strong> — Nummern werden automatisch erhöht</li></ul><h2 id="funktionsumschalter" tabindex="-1">Funktionsumschalter <a class="header-anchor" href="#funktionsumschalter" aria-label="Permalink to &quot;Funktionsumschalter&quot;">​</a></h2><p>Aktivieren oder deaktivieren Sie optionale Module:</p><table tabindex="0"><thead><tr><th>Funktion</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Objekte / Vermögenswerte</strong></td><td>Mietobjekt- und Vermögensverwaltung</td></tr><tr><td><strong>Verträge</strong></td><td>Wiederkehrende Dienstleistungs- und Mietverträge</td></tr><tr><td><strong>Projekte</strong></td><td>Projektbasierte Arbeitsverfolgung</td></tr><tr><td><strong>Angebote</strong></td><td>Angebotsverwaltung</td></tr><tr><td><strong>Reverse-Charge</strong></td><td>Innergemeinschaftliche B2B-Rechnungsstellung</td></tr><tr><td><strong>KI-Vorschläge</strong></td><td>Intelligente Kategorisierungsempfehlungen</td></tr><tr><td><strong>Belegscanner</strong></td><td>OCR-Ausgabenerfassung</td></tr><tr><td><strong>Textprüfung</strong></td><td>Grammatik- und Rechtschreibprüfung</td></tr></tbody></table><p>Deaktivierte Module werden in der Navigation ausgeblendet, um Ihren Arbeitsbereich fokussiert zu halten.</p><h2 id="pdf-vorlage" tabindex="-1">PDF-Vorlage <a class="header-anchor" href="#pdf-vorlage" aria-label="Permalink to &quot;PDF-Vorlage&quot;">​</a></h2><p>Passen Sie das Layout und das Erscheinungsbild Ihrer generierten PDFs an:</p><ul><li>Feldpositionierung</li><li>Sichtbarkeit von Informationen</li><li>Schriftart und Größe</li><li>Logo-Platzierung</li></ul><p>Greifen Sie auf den vollständigen <strong>PDF-Editor</strong> für visuelle Drag-and-Drop-Anpassung über Unternehmen &gt; PDF-Editor zu.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Erweiterte PDF-Anpassung erfordert den <strong>Pro</strong>-Tarif oder höher.</p></div><h2 id="teammitglieder" tabindex="-1">Teammitglieder <a class="header-anchor" href="#teammitglieder" aria-label="Permalink to &quot;Teammitglieder&quot;">​</a></h2><p>Sehen und verwalten Sie Ihr Team über die Unternehmensseite. Siehe <a href="/de/settings/team">Teamverwaltung</a> für Details.</p>',39)])])}const c=n(i,[["render",s]]);export{m as __pageData,c as default};
